When('the user fills Title from test data', async function () {
  const _d = this.contactUsData?.[0] || this.ownershipData?.[0] || this.genesisRyiData?.[0] || this.contactDealerData?.[0] || this.testDriveData?.[0] || {};
  // Also scan allConfluenceData for a row that contains a Title-like field
  if (!_d['Title'] && !_d['Salutation'] && this.allConfluenceData) {
    for (const rows of Object.values(this.allConfluenceData)) {
      if (Array.isArray(rows) && rows[0] && (rows[0]['Title'] || rows[0]['Salutation'])) {
        Object.assign(_d, rows[0]); break;
      }
    }
  }
  const _t = (_d['Title'] || _d['Salutation'] || _d['title'] || 'Mr').toString();
  const _header = this._activeModalHeader || 'Book a valuation';
  const modal = this.page.locator('.modal-wrapper').filter({ has: this.page.locator(`.modal-header:has-text("${_header}")`) }).first();
  const _tSelStr = "select[name*='title' i], select[id*='title' i], select[name*='salut' i], input[name*='salut' i], input[id*='salut' i], input[id*='title' i]";
  let _tSel = modal.locator(_tSelStr).first();
  if ((await _tSel.count().catch(() => 0)) === 0 || !(await _tSel.isVisible().catch(() => false))) {
    _tSel = this.page.locator(_tSelStr).first();
  }
  if ((await _tSel.count()) > 0) {
    const _tag = await _tSel.evaluate(el => el.tagName.toLowerCase());
    if (_tag === 'select') {
      await _tSel.selectOption({ label: _t }).catch(async () => {
        const _opts = await _tSel.locator('option').allTextContents();
        const _m = _opts.find(o => o.trim().toLowerCase().includes(_t.toLowerCase())) || _opts[1];
        if (_m) await _tSel.selectOption({ label: _m.trim() }).catch(() => {});
      });
      console.log(`📋 Entered Title via native select: "${_t}"`);
      await this.page.waitForTimeout(300);
      return;
    }
  }

  // Custom (non-native) Title dropdown — click the trigger labelled "Title" then click the option.
  const _opened = await this.page.evaluate(() => {
    const PLACE = /^title\*?$|select title|^title\s*$/i;
    let trigger = null;
    for (const el of document.querySelectorAll('input, button, [role="button"], [role="combobox"], div, span, label')) {
      const t = (el.placeholder || el.getAttribute('aria-label') || el.getAttribute('data-placeholder') || el.innerText || '').trim();
      if (!t) continue;
      if (PLACE.test(t) && t.length < 40) {
        const r = el.getBoundingClientRect();
        if (r.width > 30 && r.height > 16) { trigger = el; break; }
      }
    }
    if (!trigger) return { ok: false };
    let walk = trigger, clicker = trigger;
    for (let d = 0; d < 6 && walk; d++) {
      const cs = getComputedStyle(walk);
      const isClickable = walk.tagName === 'BUTTON' || walk.getAttribute('role') === 'button' ||
        walk.getAttribute('role') === 'combobox' || cs.cursor === 'pointer' ||
        /select|dropdown|combobox|trigger/i.test(walk.className?.toString?.() || '');
      if (isClickable) { clicker = walk; break; }
      walk = walk.parentElement;
    }
    clicker.scrollIntoView({ block: 'center' });
    clicker.click();
    return { ok: true };
  });
  if (_opened.ok) {
    await this.page.waitForTimeout(600);
    const _option = this.page.locator(
      `[role="option"]:has-text("${_t}"):visible, ` +
      `li:has-text("${_t}"):visible, ` +
      `[class*="option" i]:has-text("${_t}"):visible, ` +
      `[class*="item" i]:has-text("${_t}"):visible, ` +
      `span:has-text("${_t}"):visible`
    ).first();
    if ((await _option.count()) > 0) {
      await _option.click({ timeout: 3000 }).catch(() => {});
      console.log(`📋 Entered Title via custom dropdown: "${_t}"`);
      await this.page.waitForTimeout(300);
      return;
    }
    // Exact-text JS click fallback
    const _ok = await this.page.evaluate((label) => {
      const re = new RegExp(`^\\s*${label.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')}\\s*$`, 'i');
      const all = Array.from(document.querySelectorAll('li, span, a, button, div, [role="option"]'));
      const v = all.filter(el => {
        const r = el.getBoundingClientRect();
        if (r.width < 5 || r.height < 5) return false;
        const cs = getComputedStyle(el);
        if (cs.display === 'none' || cs.visibility === 'hidden') return false;
        return el.children.length === 0 || el.tagName === 'LI';
      });
      const m = v.find(el => re.test((el.innerText || el.textContent || '').trim()));
      if (m) { (m.closest('li, [role="option"], button') || m).click(); return true; }
      return false;
    }, _t);
    if (_ok) console.log(`📋 Entered Title via JS click: "${_t}"`);
    else console.log(`⚠️  Title option "${_t}" not found in opened dropdown`);
  } else {
    console.log('⚠️  Title field/trigger not found — skipping');
  }
  await this.page.waitForTimeout(300);
});

